        AscendC::DataCopy(bLocal, bGm_, hiddenSize_);
        inQueueB_.EnQue(bLocal);

        for (uint32_t row = startRow; row < endRow; ++row) {
            uint32_t offset = row * hiddenSize_;

            // Load x row (double buffering: use alternating buffers)
            AscendC::LocalTensor<float> xLocal = inQueueX_.AllocTensor<float>();
            AscendC::DataCopy(xLocal, xGm_[offset], hiddenSize_);

            // Allocate output buffer
            AscendC::LocalTensor<float> yLocal = outQueueY_.AllocTensor<float>();
            // Temporary tensors
            AscendC::LocalTensor<float> diffLocal = tmpBuf_.AllocTensor<float>();
            AscendC::LocalTensor<float> sqrLocal = tmpBuf_.AllocTensor<float>();
            AscendC::LocalTensor<float> sumLocal = tmpBuf_.AllocTensor<float>();
            AscendC::LocalTensor<float> meanVecLocal = tmpBuf_.AllocTensor<float>();

            // Compute meanX = sum(x) / N
            AscendC::ReduceAdd(sumLocal, xLocal, AscendC::VecBinaryOp::ADD, hiddenSize_);
